import{drop}from"@hyperjump/pact";import*as Browser from"@hyperjump/browser";import*as Instance from"../instance.js";import{getKeywordName,Validation}from"../experimental.js";const id="https://json-schema.org/keyword/items",compile=async(e,t,r)=>{var o=getKeywordName(e.document.dialectId,"https://json-schema.org/keyword/prefixItems"),o=await Browser.step(o,r);return["array"===Browser.typeOf(o)?Browser.length(o):0,await Validation.compile(e,t)]},interpret=([e,t],r,o)=>{if("array"!==Instance.typeOf(r))return!0;let a=!0;for(const i of drop(e,Instance.iter(r)))Validation.interpret(t,i,o)||(a=!1);return a},simpleApplicator=!0,collectEvaluatedItems=(t,r,e)=>{if(!interpret(t,r,e))return!1;const o=new Set;for(let e=t[0];e<Instance.length(r);e++)o.add(e);return o};export default{id:id,compile:compile,interpret:interpret,simpleApplicator:simpleApplicator,collectEvaluatedItems:collectEvaluatedItems};